   223|      headers: { Authorization: `Bearer ${token}`, Accept: 'application/vnd.github+json' },
   224|    });
   225|    if (!res.ok) return { sha: null, message: null, date: null, error: `GitHub API ${res.status}` };
   226|    const data = await res.json() as { sha?: string; commit?: { message?: string; author?: { date?: string } } };
   227|    return {
   228|      sha: data.sha ?? null,
   229|      message: data.commit?.message ?? null,
