/**
 * IVX Live Deployment Dashboard
 *
 * Real-time status display for all deployment tools:
 *   - GitHub HEAD commit
 *   - Render deployed commit
 *   - Production commit
 *   - Commit match status
 *   - Auto-deploy status
 *   - Supabase status
 *   - Errors and blockers
 *   - Next automatic action
 */

import React, { useCallback, useEffect, useState } from 'react';
import {
  View,
  Text,
  ScrollView,
  TouchableOpacity,
  ActivityIndicator,
  StyleSheet,
} from 'react-native';
import { RefreshCw, CheckCircle, XCircle, AlertTriangle, ExternalLink, ChevronRight } from 'lucide-react-native';

// ─── Types ───────────────────────────────────────────────────────────

type BrainStatus = 'healthy' | 'degraded' | 'stale' | 'broken' | 'unverified';

interface DashboardData {
  brain: {
    overallStatus: BrainStatus;
    decision: string;
    commitMatch: boolean;
    commits: { github: string | null; render: string | null; production: string | null };
    platforms: Array<{ platform: string; ok: boolean; configured: boolean; error: string | null; details: Record<string, unknown> }>;
    deployInProgress: boolean;
    latestDeploy: { id: string | null; status: string | null; duration: number | null };
    credentials: { total: number; valid: number; missing: number; failed: number };
    errors: string[];
    blockers: string[];
    nextAction: string;
    autoRepairAvailable: boolean;
    ownerApprovalRequired: boolean;
  };
  evidence: {
    endpoints: Array<{ name: string; ok: boolean; status: number | null; latencyMs: number; error: string | null }>;
    commitMatch: boolean;
    commits: Array<{ source: string; shortSha: string | null; error: string | null }>;
    allEndpointsOk: boolean;
    healthStatus: string | null;
  };
  credentials: {
    summary: { total: number; valid: number; missing: number; failed: number };
    gaps: string[];
    recommendations: string[];
  };
  timestamp: string;
}

// ─── Styles ───────────────────────────────────────────────────────────

const COLORS = {
  bg: '#0a0a0f',
  card: '#14141f',
  cardBorder: '#1e1e2e',
  text: '#e4e4f0',
  textSecondary: '#8888a0',
  green: '#22c55e',
  greenBg: 'rgba(34, 197, 94, 0.1)',
  red: '#ef4444',
  redBg: 'rgba(239, 68, 68, 0.1)',
  yellow: '#f59e0b',
  yellowBg: 'rgba(245, 158, 11, 0.1)',
  blue: '#3b82f6',
  blueBg: 'rgba(59, 130, 246, 0.1)',
  purple: '#8b5cf6',
  accent: '#6366f1',
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: COLORS.bg,
  },
  header: {
    paddingHorizontal: 16,
    paddingTop: 16,
    paddingBottom: 12,
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
  },
  title: {
    fontSize: 20,
    fontWeight: '700',
    color: COLORS.text,
  },
  refreshButton: {
    padding: 8,
    borderRadius: 8,
    backgroundColor: COLORS.card,
  },
  statusBadge: {
    marginHorizontal: 16,
    marginBottom: 12,
    paddingHorizontal: 12,
    paddingVertical: 6,
    borderRadius: 8,
    alignSelf: 'flex-start',
  },
  statusText: {
    fontSize: 12,
    fontWeight: '600',
    textTransform: 'uppercase',
    letterSpacing: 0.5,
  },
  section: {
    marginHorizontal: 16,
    marginBottom: 16,
  },
  sectionTitle: {
    fontSize: 14,
    fontWeight: '600',
    color: COLORS.textSecondary,
    marginBottom: 8,
    textTransform: 'uppercase',
    letterSpacing: 0.5,
  },
  card: {
    backgroundColor: COLORS.card,
    borderRadius: 12,
    borderWidth: 1,
    borderColor: COLORS.cardBorder,
    padding: 16,
    marginBottom: 8,
  },
  commitRow: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: 4,
  },
  commitSource: {
    fontSize: 12,
    color: COLORS.textSecondary,
    fontWeight: '500',
  },
  commitSha: {
    fontSize: 14,
    fontFamily: 'monospace',
    color: COLORS.text,
    fontWeight: '600',
  },
  platformRow: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'space-between',
    paddingVertical: 6,
    borderBottomWidth: 1,
    borderBottomColor: COLORS.cardBorder,
  },
  platformName: {
    fontSize: 13,
    color: COLORS.text,
    fontWeight: '600',
    textTransform: 'capitalize',
  },
  platformStatus: {
    fontSize: 12,
    fontWeight: '500',
  },
  statGrid: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    gap: 8,
  },
  statCard: {
    flex: 1,
    minWidth: '45%',
    backgroundColor: COLORS.card,
    borderRadius: 12,
    borderWidth: 1,
    borderColor: COLORS.cardBorder,
    padding: 12,
    alignItems: 'center',
  },
  statValue: {
    fontSize: 28,
    fontWeight: '700',
    color: COLORS.text,
  },
  statLabel: {
    fontSize: 11,
    color: COLORS.textSecondary,
    marginTop: 2,
    textTransform: 'uppercase',
  },
  errorCard: {
    backgroundColor: COLORS.redBg,
    borderRadius: 8,
    padding: 10,
    marginBottom: 6,
    borderLeftWidth: 3,
    borderLeftColor: COLORS.red,
  },
  errorText: {
    fontSize: 12,
    color: COLORS.red,
    lineHeight: 18,
  },
  nextActionCard: {
    backgroundColor: COLORS.blueBg,
    borderRadius: 12,
    padding: 14,
    marginHorizontal: 16,
    marginBottom: 16,
    borderLeftWidth: 3,
    borderLeftColor: COLORS.blue,
  },
  nextActionText: {
    fontSize: 13,
    color: COLORS.blue,
    fontWeight: '500',
    lineHeight: 20,
  },
  endpointRow: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'space-between',
    paddingVertical: 4,
  },
  endpointName: {
    fontSize: 12,
    color: COLORS.textSecondary,
    flex: 1,
  },
  endpointStatus: {
    fontSize: 11,
    color: COLORS.textSecondary,
    marginRight: 8,
  },
  loadingContainer: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    backgroundColor: COLORS.bg,
  },
  loadingText: {
    color: COLORS.textSecondary,
    marginTop: 12,
    fontSize: 14,
  },
  deployProgress: {
    backgroundColor: COLORS.yellowBg,
    borderRadius: 8,
    padding: 10,
    marginHorizontal: 16,
    marginBottom: 16,
    flexDirection: 'row',
    alignItems: 'center',
    gap: 8,
  },
});

// ─── Component ────────────────────────────────────────────────────────

export default function DeploymentDashboard() {
  const [data, setData] = useState<DashboardData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const API_BASE = process.env.EXPO_PUBLIC_API_BASE_URL ?? 'https://api.ivxholding.com';

  const fetchDashboard = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch(`${API_BASE}/api/ivx/deploy-tools/dashboard`, {
        headers: { Accept: 'application/json' },
        signal: AbortSignal.timeout(30000),
      });
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const json = await res.json() as { ok: boolean; brain?: unknown; evidence?: unknown; credentials?: unknown } & Record<string, unknown>;
      if (!json.ok) throw new Error('Dashboard returned not-ok');
      setData(json as unknown as DashboardData);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load dashboard');
    } finally {
      setLoading(false);
    }
  }, [API_BASE]);

  useEffect(() => {
    fetchDashboard();
  }, [fetchDashboard]);

  if (loading && !data) {
    return (
      <View style={styles.loadingContainer}>
